const fs = require('node:fs');
const values = JSON.parse(fs.readFileSync(0, 'utf8'));
if (!Array.isArray(values)) process.exit(1);
console.log(JSON.stringify(values.filter((value) => value % 2 === 0).map((value) => value * 2)));
